"use client";
import { useState, useEffect, useRef, Suspense } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { supabase } from "@/lib/supabase";
import Link from "next/link";

interface Message {
    id: string;
    role: "user" | "assistant";
    content: string;
    sources?: { name: string; page?: number }[];
}

function ChatContent() {
    const searchParams = useSearchParams();
    const router = useRouter();
    const moduleParam = searchParams.get("module") || "contabilidad";

    const [messages, setMessages] = useState<Message[]>([
        {
            id: "welcome",
            role: "assistant",
            content: `Hola. Soy tu asistente de IA especializado en normativa de **${moduleParam.charAt(0).toUpperCase() + moduleParam.slice(1)}**. ??En qu?? puedo ayudarte hoy?`,
        }
    ]);
    const [input, setInput] = useState("");
    const [loading, setLoading] = useState(false);
    const [userPlan, setUserPlan] = useState("B??sico");
    const [showExportWizard, setShowExportWizard] = useState(false);
    const [showAnalysisWizard, setShowAnalysisWizard] = useState(false);
    const [exportStep, setExportStep] = useState(1);
    const [analysisStep, setAnalysisStep] = useState(1);
    const [exportFormat, setExportFormat] = useState<"pdf" | "word" | "txt">("pdf");
    const [userProfile, setUserProfile] = useState<any>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const [history, setHistory] = useState<any[]>([]);

    useEffect(() => {
        const fetchData = async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                // Fetch Plan
                const { data: profile } = await supabase
                    .from("profiles")
                    .select("*")
                    .eq("id", user.id)
                    .maybeSingle();
                if (profile) {
                    setUserPlan(profile.plan || "B??sico");
                    setUserProfile(profile);
                }

                // Fetch History
                const { data: logs } = await supabase
                    .from("query_logs")
                    .select("*")
                    .eq("user_id", user.id)
                    .eq("module_id", moduleParam)
                    .order("created_at", { ascending: false })
                    .limit(10);
                if (logs) setHistory(logs);
            }
        };
        fetchData();
    }, [moduleParam]);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || loading) return;

        const userMessage: Message = {
            id: Date.now().toString(),
            role: "user",
            content: input,
        };

        setMessages(prev => [...prev, userMessage]);
        const currentInput = input;
        setInput("");
        setLoading(true);

        try {
            const apiKey = "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";

            // 1. INTENT CLASSIFIER (Router Multi-Label)
            const classifierResponse = await fetch("https://api.groq.com/openai/v1/chat/completions", {
                method: "POST",
                headers: { "Authorization": `Bearer ${apiKey}`, "Content-Type": "application/json" },
                body: JSON.stringify({
                    model: "llama-3.3-70b-versatile",
                    messages: [
                        {
                            role: "system",
                            content: `Act??a como un router clasificador de intenciones. Analiza la consulta y asigna una probabilidad (0.0 a 1.0) a cada m??dulo: contabilidad, laboral, tributaria, auditoria.
                            Devuelve ??NICAMENTE un objeto JSON. Ejemplo: { "contabilidad": 0.9, "tributaria": 0.1 }`
                        },
                        { role: "user", content: currentInput }
                    ],
                    response_format: { type: "json_object" }
                })
            });
            const classData = await classifierResponse.json();
            const scores = JSON.parse(classData.choices[0].message.content);

            const activeModules = Object.entries(scores)
                .filter(([_, s]: any) => s >= 0.3)
                .map(([m]) => m);

            const isCrossing = activeModules.length > 1;

            const isBasic = userPlan.includes("B??sico") || userPlan === "B??sico";
            const isCrossingBlocked = isBasic && isCrossing;

            if (isCrossingBlocked) {
                const assistantMessage: Message = {
                    id: Date.now().toString(),
                    role: "assistant",
                    content: `?????? **Esta consulta involucra m??dulos adicionales no incluidos en tu plan.**\n\nDetectamos que tu pregunta requiere conocimientos de: **${activeModules.join(", ")}**. \n\nTu **Plan B??sico (Modo Informativo)** est?? limitado a consultas de un solo m??dulo a la vez. Para que la IA cruce normativas y te brinde una estrategia integral, por favor sube a un plan **Pro** o **Premium**.`
                };
                setMessages(prev => [...prev, assistantMessage]);
                setLoading(false);
                return;
            }

            let systemPrompt = `Eres Sooferline IA. 
            CONTEXTO: M??dulo actual: ${moduleParam}. Plan: ${userPlan}. 
            REGLAS DE RESPUESTA:
            - Si el plan es B??sico (Modo Informativo): Solo responde sobre ${moduleParam}.
            - Si el plan es Pro (Modo Asesor): Cruza informaci??n entre los m??dulos detectados (${activeModules.join(", ")}) solo si son relevantes.
            - Si el plan es Premium (Modo Estratega): Eres un consultor experto. Cruza TODA la normativa necesaria (${activeModules.join(", ")}) para dar una soluci??n comparativa y estrat??gica.
            - Responde de forma profesional, clara y directa.`;

            const response = await fetch("https://api.groq.com/openai/v1/chat/completions", {
                method: "POST",
                headers: { "Authorization": `Bearer ${apiKey}`, "Content-Type": "application/json" },
                body: JSON.stringify({
                    model: "llama-3.3-70b-versatile",
                    messages: [
                        { role: "system", content: systemPrompt },
                        { role: "user", content: currentInput }
                    ],
                    temperature: 0.6,
                })
            });

            const data = await response.json();
            const content = data.choices[0]?.message?.content || "Lo siento, hubo un problema.";

            const finalSources = activeModules.length > 0
                ? activeModules.map(m => ({ name: m.charAt(0).toUpperCase() + m.slice(1) }))
                : [{ name: moduleParam.charAt(0).toUpperCase() + moduleParam.slice(1) }];

            const assistantMessage: Message = {
                id: Date.now().toString(),
                role: "assistant",
                content: content,
                sources: finalSources
            };

            setMessages(prev => [...prev, assistantMessage]);
            setLoading(false);

            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                await supabase.from("query_logs").insert({
                    user_id: user.id,
                    query: currentInput,
                    response: content,
                    module_id: moduleParam,
                    plan_at_time: userPlan
                });
                setHistory(prev => [{ query: currentInput, created_at: new Date().toISOString() }, ...prev.slice(0, 9)]);
            }

        } catch (error) {
            console.error("Chat error:", error);
            setLoading(false);
        }
    };

    return (
        <div className="flex h-screen bg-background-light dark:bg-background-dark font-display overflow-hidden">
            <aside className="hidden md:flex w-72 flex-col bg-white/50 dark:bg-slate-900/50 border-r border-slate-200 dark:border-slate-800 backdrop-blur-xl">
                <div className="p-6 border-b border-slate-200 dark:border-slate-800 flex items-center gap-3">
                    <div className="bg-primary size-8 rounded-lg flex items-center justify-center text-white">
                        <span className="material-symbols-outlined text-lg">auto_awesome</span>
                    </div>
                    <span className="font-bold text-slate-900 dark:text-white">Assistant IA</span>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-4 text-slate-900 dark:text-slate-100">
                    <div className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Historial Reciente</div>
                    {history.length > 0 ? history.map((h, i) => (
                        <button key={i} onClick={() => setInput(h.query)} className="w-full text-left p-3 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 transition-all text-sm font-medium text-slate-600 dark:text-slate-400 truncate">{h.query}</button>
                    )) : (
                        <p className="px-2 text-[10px] text-slate-400 font-bold italic uppercase tracking-wider">No hay consultas previas</p>
                    )}
                </div>
                <div className="p-4 border-t border-slate-200 dark:border-slate-800">
                    <Link href="/dashboard" className="flex items-center gap-2 p-3 text-sm font-bold text-slate-600 dark:text-slate-400 hover:text-primary transition-colors">
                        <span className="material-symbols-outlined">dashboard</span>
                        Volver al Dashboard
                    </Link>
                </div>
            </aside>

            <main className="flex-1 flex flex-col relative">
                <header className="h-16 flex items-center justify-between px-6 bg-white/80 dark:bg-slate-900/80 border-b border-slate-200 dark:border-slate-800 backdrop-blur-md z-10">
                    <div className="flex items-center gap-3">
                        <Link href="/dashboard" className="md:hidden size-8 flex items-center justify-center">
                            <span className="material-symbols-outlined">arrow_back</span>
                        </Link>
                        <div className="flex flex-col">
                            <span className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tight">M??dulo: {moduleParam}</span>
                            <div className="flex items-center gap-1.5">
                                <span className="size-2 rounded-full bg-green-500 animate-pulse"></span>
                                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">IA Activa y Precisando fuentes</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <button onClick={() => setShowExportWizard(true)} className="flex items-center gap-2 px-3 py-1.5 bg-primary/10 text-primary rounded-lg text-xs font-bold hover:bg-primary hover:text-white transition-all transform active:scale-95 shadow-sm">
                            <span className="material-symbols-outlined text-sm">download</span>
                            Exportar Informe
                        </button>
                    </div>
                </header>

                <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 flex flex-col items-center">
                    <div className="w-full max-w-3xl space-y-6 pb-32">
                        {messages.map((msg) => (
                            <div key={msg.id} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                                <div className={`max-w-[85%] md:max-w-[75%] rounded-2xl p-4 md:p-5 shadow-sm ${msg.role === "user" ? "bg-primary text-white" : "bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 text-slate-800 dark:text-slate-200"}`}>
                                    <div className="text-sm md:text-base leading-relaxed whitespace-pre-wrap">{msg.content}</div>
                                    {msg.sources && msg.sources.length > 0 && (
                                        <div className="mt-4 pt-3 border-t border-slate-100 dark:border-slate-700/50">
                                            <p className="text-[10px] uppercase font-black text-slate-400 mb-2 tracking-widest">Fuentes Consultadas:</p>
                                            <div className="flex flex-wrap gap-2">
                                                {msg.sources.map((s, i) => {
                                                    const isBasicPlan = userPlan === "B??sico" || userPlan.toLowerCase().includes("basico");
                                                    return (
                                                        <button key={i} onClick={() => {
                                                            if (isBasicPlan) alert("?????? Tu acceso a las fuentes est?? bloqueado en el Plan B??sico.");
                                                            else router.push(`/biblioteca?module=${moduleParam}&doc=${encodeURIComponent(s.name)}&from=chat`);
                                                        }} className={`px-2 py-1 rounded-md border flex items-center gap-1.5 transition-all ${!isBasicPlan ? "bg-primary/5 dark:bg-primary/20 border-primary/10 hover:bg-primary hover:text-white group" : "bg-slate-50 border-slate-100 text-slate-400 opacity-60"}`}>
                                                            <span className={`material-symbols-outlined text-[12px] ${!isBasicPlan ? "group-hover:text-white text-primary" : "text-slate-400"}`}>{isBasicPlan ? "lock" : "description"}</span>
                                                            <span className="text-[10px] font-bold truncate max-w-[120px]">{s.name}</span>
                                                        </button>
                                                    );
                                                })}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}
                        {loading && <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">IA Analizando...</div>}
                        <div ref={messagesEndRef} />
                    </div>
                </div>

                <div className="p-4 md:p-8 flex justify-center">
                    <form onSubmit={handleSend} className="w-full max-w-3xl bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 p-2 flex items-center gap-2">
                        <button type="button" onClick={() => userPlan !== "B??sico" && setShowAnalysisWizard(true)} disabled={userPlan === "B??sico"} className="p-3 text-slate-400 hover:text-primary disabled:opacity-30"><span className="material-symbols-outlined">attach_file</span></button>
                        <input value={input} onChange={(e) => setInput(e.target.value)} placeholder="Haz tu consulta normativa aqu??..." className="flex-1 bg-transparent border-none outline-none px-2 text-base" />
                        <button type="submit" disabled={!input.trim() || loading} className="size-12 bg-primary text-white rounded-xl shadow-lg flex items-center justify-center transition-all"><span className="material-symbols-outlined">send</span></button>
                    </form>
                </div>
            </main>

            {showExportWizard && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setShowExportWizard(false)}></div>
                    <div className="relative w-full max-w-lg bg-white dark:bg-slate-900 rounded-3xl p-8 shadow-2xl">
                        <h2 className="text-xl font-black mb-4">Exportar Informe ({exportStep}/3)</h2>
                        {exportStep === 1 && (
                            <div className="space-y-3">
                                <button onClick={() => { setExportFormat("pdf"); setExportStep(2); }} className="w-full p-4 rounded-xl border-2 hover:border-primary text-left font-bold">PDF Premium</button>
                                <button onClick={() => { setExportFormat("txt"); setExportStep(2); }} className="w-full p-4 rounded-xl border-2 hover:border-primary text-left font-bold">Texto Plano (.txt)</button>
                            </div>
                        )}
                        {exportStep === 2 && (
                            <div className="space-y-4">
                                <div className="font-bold">Personaliza tu informe...</div>
                                <button onClick={() => setExportStep(3)} className="w-full py-4 bg-primary text-white rounded-xl font-bold">Siguiente</button>
                                <button onClick={() => setExportStep(1)} className="w-full py-4 border rounded-xl font-bold">Atr??s</button>
                            </div>
                        )}
                        {exportStep === 3 && (
                            <div className="text-center">
                                <button onClick={() => {
                                    const reportText = messages.map(m => `[${m.role.toUpperCase()}]: ${m.content}`).join("\n\n");
                                    const blob = new Blob([reportText], { type: 'text/plain' });
                                    const url = window.URL.createObjectURL(blob);
                                    const a = document.createElement('a');
                                    a.href = url;
                                    a.download = `Informe_${moduleParam}.txt`;
                                    a.click();
                                    setShowExportWizard(false);
                                    setExportStep(1);
                                }} className="w-full py-4 bg-primary text-white rounded-xl font-bold">Generar y Descargar</button>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {showAnalysisWizard && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setShowAnalysisWizard(false)}></div>
                    <div className="relative w-full max-w-lg bg-white dark:bg-slate-900 rounded-3xl p-8 shadow-2xl text-center">
                        <span className="material-symbols-outlined text-4xl text-primary mb-4">upload_file</span>
                        <h2 className="text-xl font-black mb-2">An??lisis de Documentos</h2>
                        <p className="text-sm text-slate-500 mb-6">Sube tu archivo para compararlo con la normativa vigente.</p>
                        <button onClick={() => setShowAnalysisWizard(false)} className="w-full py-4 bg-primary text-white rounded-xl font-bold">Cerrar</button>
                    </div>
                </div>
            )}
        </div>
    );
}

export default function ChatPage() {
    return (
        <Suspense fallback={<div className="h-screen flex items-center justify-center"><div className="animate-spin rounded-full h-12 w-12 border-t-2 border-primary"></div></div>}>
            <ChatContent />
        </Suspense>
    );
}

"use client";
import { useState, useEffect, Suspense } from "react";
import { supabase } from "@/lib/supabase";
import Navbar from "@/components/Navbar";
import Link from "next/link";
import { useRouter } from "next/navigation";

function BibliotecaComprasContent() {
    const [purchases, setPurchases] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const router = useRouter();

    useEffect(() => {
        fetchPurchases();
    }, []);

    const fetchPurchases = async () => {
        setLoading(true);
        // Validar sesi??n
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) {
            router.push("/auth?redirect=/mis-compras");
            return;
        }

        // Obtener las compras haciendo un JOIN con la tabla de productos
        const { data, error } = await supabase
            .from("user_purchases")
            .select(`
                id,
                created_at,
                product:products (id, title, image_url, type, version, metadata, file_url)
            `)
            .eq("user_id", session.user.id)
            .order("created_at", { ascending: false });

        if (error) {
            console.error("Error obteniendo compras:", error);
        } else if (data) {
            // Flatten the response
            const formatted = data.map((item: any) => ({
                purchase_id: item.id,
                date: new Date(item.created_at).toLocaleDateString("es-CL"),
                product: item.product
            }));
            setPurchases(formatted);
        }

        setLoading(false);
    };

    const handleView = (product: any) => {
        if (product.metadata && product.metadata.book_id) {
            router.push(`/biblioteca?doc=${encodeURIComponent(product.title)}&id=${product.metadata.book_id}`);
        } else if (product.file_url) {
            window.open(product.file_url, '_blank');
        } else {
            alert("Este recurso est?? siendo preparado para su visualizaci??n online.");
        }
    };

    const handleDownload = (product: any) => {
        if (product.file_url) {
            const link = document.createElement("a");
            link.href = product.file_url;
            link.target = "_blank"; // Mejor abrir en nueva si el bucket la tira
            link.download = `${product.title}.pdf`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        } else {
            alert("Este recurso s??lo est?? disponible para ver online o su archivo de descarga est?? en proceso.");
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 font-display">
            <Navbar />
            <main className="max-w-7xl mx-auto px-6 py-12">
                <div className="mb-10 text-center md:text-left">
                    <div className="flex items-center gap-2 mb-2 justify-center md:justify-start">
                        <span className="material-symbols-outlined text-primary text-3xl">local_library</span>
                        <p className="text-[12px] font-black uppercase tracking-[0.2em] text-slate-400">Archivos Personales</p>
                    </div>
                    <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none mb-3">Mi Biblioteca</h1>
                    <p className="text-slate-500 font-medium">Aqu?? encontrar??s todos los cursos, plantillas y herramientas que has adquirido.</p>
                </div>

                {loading ? (
                    <div className="py-20 flex flex-col items-center justify-center">
                        <div className="size-16 border-4 border-slate-200 border-t-primary rounded-full animate-spin mb-4"></div>
                        <p className="font-black uppercase tracking-widest text-xs text-slate-400">Cargando tus recursos...</p>
                    </div>
                ) : purchases.length === 0 ? (
                    <div className="py-20 text-center bg-white rounded-[40px] border border-slate-100 shadow-xl shadow-slate-200/50">
                        <span className="material-symbols-outlined text-6xl text-slate-200 mb-4">folder_off</span>
                        <h3 className="text-xl font-black text-slate-800 mb-2">A??n no hay compras</h3>
                        <p className="text-slate-500 mb-6">Explora nuestra tienda para adquirir conocimientos y herramientas incre??bles.</p>
                        <Link href="/tienda" className="px-8 py-4 bg-primary text-white rounded-2xl font-black uppercase tracking-widest shadow-lg shadow-primary/20 hover:scale-[1.02] transition-all inline-block">
                            Ir a la Tienda
                        </Link>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {purchases.map((item) => {
                            const p = Array.isArray(item.product) ? item.product[0] : item.product; // Si hay multiple matching (no deberia pasar)

                            if (!p) return null;

                            return (
                                <div key={item.purchase_id} className="bg-white rounded-[32px] p-6 shadow-xl shadow-slate-200/50 border border-slate-100 flex flex-col hover:border-primary/30 transition-all group">
                                    <div className="flex gap-4 mb-6">
                                        <img src={p.image_url} alt={p.title} className="size-20 bg-slate-100 rounded-xl object-cover" />
                                        <div>
                                            <span className="px-2 py-0.5 bg-primary/10 text-primary rounded text-[9px] font-bold inline-block mb-1">{p.type}</span>
                                            <h3 className="font-bold text-slate-800 leading-tight line-clamp-2" title={p.title}>{p.title}</h3>
                                            <p className="text-[10px] text-slate-400 mt-1 font-bold">Comprado: {item.date}</p>
                                        </div>
                                    </div>

                                    <div className="mt-auto grid grid-cols-2 gap-3 pt-4 border-t border-slate-50">
                                        <button
                                            onClick={() => handleView(p)}
                                            className="flex items-center justify-center gap-2 py-3 bg-slate-50 hover:bg-slate-100 text-slate-600 rounded-xl transition-colors font-bold text-[10px] uppercase tracking-widest"
                                        >
                                            <span className="material-symbols-outlined text-sm">visibility</span> Ver
                                        </button>
                                        <button
                                            onClick={() => handleDownload(p)}
                                            className="flex items-center justify-center gap-2 py-3 bg-primary/10 hover:bg-primary hover:text-white text-primary rounded-xl transition-colors font-bold text-[10px] uppercase tracking-widest"
                                        >
                                            <span className="material-symbols-outlined text-sm">cloud_download</span> Descargar
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </main>
        </div>
    );
}

export default function MiBibliotecaPage() {
    return (
        <Suspense fallback={<div className="min-h-screen bg-slate-50 flex items-center justify-center">Cargando...</div>}>
            <BibliotecaComprasContent />
        </Suspense>
    );
}

"use client";
import { useState, useEffect } from "react";
import { supabase } from "@/lib/supabase";
import { useRouter } from "next/navigation";
import Link from "next/link";

export default function PlanesPage() {
    const router = useRouter();
    const [loading, setLoading] = useState(true);
    const [userPlan, setUserPlan] = useState("B??sico");
    const [updating, setUpdating] = useState(false);
    const [status, setStatus] = useState("");

    useEffect(() => {
        const fetchUser = async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) {
                router.push("/login");
                return;
            }
            // Get plan from profile
            const { data: profile } = await supabase
                .from("profiles")
                .select("plan")
                .eq("id", user.id)
                .maybeSingle();

            if (profile) {
                setUserPlan(profile.plan || "B??sico");
            }
            setLoading(false);
        };
        fetchUser();
    }, [router]);

    const handleSelectPlan = async (plan: string) => {
        setUpdating(true);
        setStatus(`Confirmando cambio a Plan ${plan}...`);

        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) throw new Error("Sesi??n expirada o inv??lida.");

            // 1. Force Upsert into Profiles table
            const { error: profileError } = await supabase
                .from("profiles")
                .upsert({
                    id: user.id,
                    plan,
                    updated_at: new Date().toISOString()
                }, { onConflict: 'id' });

            if (profileError) throw profileError;

            // 2. Update Auth Metadata (to have it in session)
            const { error: authError } = await supabase.auth.updateUser({
                data: { plan: plan }
            });
            if (authError) throw authError;

            // 3. Critically force session refresh
            await supabase.auth.refreshSession();

            // Update local state
            setUserPlan(plan);
            setStatus(`????xito! Plan ${plan} activado correctamente.`);

            // 4. Short delay then refresh and redirect
            setTimeout(() => {
                router.refresh();
                router.push('/dashboard');
            }, 1000);

        } catch (err: any) {
            console.error("Plan update error:", err);
            setStatus("Error: " + (err.message || "No se pudo actualizar el plan"));
        } finally {
            setUpdating(false);
        }
    };

    const plans = [
        {
            id: "B??sico",
            name: "Plan B??sico (Modo Informativo)",
            price: "$0",
            period: "/mes (Prueba)",
            features: [
                "1 M??dulo especializado (Actual)",
                "NO puede cruzar m??dulos",
                "Consulta de normativa base",
                "Ver Biblioteca (Portada/??ndice)",
                "Aviso de m??dulos adicionales"
            ],
            color: "slate",
            buttonText: "Plan Actual",
            active: userPlan === "B??sico"
        },
        {
            id: "Pro",
            name: "Plan Pro (Modo Informativo y Asesor)",
            price: "$0",
            period: "/mes (Prueba)",
            features: [
                "Cruza m??dulos habilitados",
                "Subida de documentos / an??lisis",
                "Visualizaci??n de texto completo",
                "Exportar informes (TXT/PDF)",
                "Consultas ilimitadas",
                "Asesor??a IA detallada"
            ],
            color: "primary",
            buttonText: "Mejorar ahora",
            popular: true,
            active: userPlan === "Pro"
        },
        {
            id: "Premium",
            name: "Plan Premium (Modo Informativo, Asesor y Estratega o Consultor)",
            price: "$0",
            period: "/mes (Prueba)",
            features: [
                "Cruce entre TODOS los m??dulos",
                "Descarga directa de Biblioteca",
                "An??lisis estrat??gico avanzado",
                "Exportar formato Word/PDF Premium",
                "Comparativa entre m??dulos",
                "Estrategias avanzadas IA"
            ],
            color: "violet-600",
            buttonText: "Obtener Premium",
            active: userPlan === "Premium"
        }
    ];

    return (
        <div className="min-h-screen bg-background-light dark:bg-background-dark font-display text-slate-900 overflow-x-hidden relative">
            {loading ? (
                <div className="min-h-screen bg-background-light flex items-center justify-center">
                    <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary"></div>
                </div>
            ) : (
                <>
                    {/* Background elements */}
                    <div className="fixed inset-0 pointer-events-none -z-10 opacity-40">
                        <div className="absolute top-[-10%] right-[-5%] w-96 h-96 bg-primary/10 rounded-full blur-[100px]"></div>
                        <div className="absolute bottom-[-10%] left-[-5%] w-96 h-96 bg-violet-500/10 rounded-full blur-[100px]"></div>
                    </div>

                    <nav className="flex items-center px-6 py-6 border-b border-slate-100 dark:border-slate-800 bg-white/50 backdrop-blur-md">
                        <Link href="/dashboard" className="flex items-center gap-2 group">
                            <span className="material-symbols-outlined text-slate-400 group-hover:text-primary transition-colors">arrow_back</span>
                            <span className="text-sm font-bold text-slate-600 group-hover:text-primary transition-colors">Dashboard</span>
                        </Link>
                        <div className="flex-1 text-center">
                            <h1 className="text-lg font-black tracking-tighter">SOOFERLINE <span className="text-primary italic">PLANES</span></h1>
                        </div>
                        <div className="w-20"></div>
                    </nav>

                    <main className="max-w-6xl mx-auto px-6 py-12">
                        <header className="text-center mb-16">
                            <h2 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-white tracking-tight mb-4 animate-in fade-in slide-in-from-top-4">
                                Elige tu potencia de <span className="bg-gradient-to-r from-primary to-violet-600 bg-clip-text text-transparent italic">An??lisis IA</span>
                            </h2>
                            <p className="text-slate-500 dark:text-slate-400 text-lg max-w-2xl mx-auto font-medium">
                                Eleva tu capacidad profesional con herramientas dise??adas para la precisi??n normativa y la automatizaci??n de informes.
                            </p>

                            {status && (
                                <div className={`mt-6 inline-block px-6 py-2 rounded-full text-sm font-bold animate-pulse ${status.includes('Error') ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                                    {status}
                                </div>
                            )}
                        </header>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            {plans.map((plan) => (
                                <div key={plan.name} className={`relative flex flex-col p-8 rounded-3xl border-2 transition-all duration-500 group ${plan.active
                                    ? "border-primary bg-primary/5 shadow-2xl shadow-primary/10 ring-4 ring-primary/5 scale-105 z-10"
                                    : "border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 hover:border-primary/50"
                                    }`}>
                                    {plan.popular && (
                                        <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-primary text-white text-[10px] font-black uppercase tracking-widest px-4 py-1 rounded-full shadow-lg shadow-primary/20">
                                            M??S POPULAR
                                        </div>
                                    )}

                                    <div className="mb-8">
                                        <h3 className={`text-xl font-black mb-2 ${plan.active ? 'text-primary' : 'text-slate-900 dark:text-white'}`}>{plan.name}</h3>
                                        <div className="flex items-baseline gap-1">
                                            <span className="text-4xl font-black text-slate-900 dark:text-white">{plan.price}</span>
                                            <span className="text-slate-400 font-bold text-sm tracking-tight">{plan.period}</span>
                                        </div>
                                    </div>

                                    <div className="space-y-4 mb-10 flex-1">
                                        {plan.features.map((feat, i) => (
                                            <div key={i} className="flex items-start gap-3">
                                                <span className={`material-symbols-outlined text-[18px] mt-0.5 ${plan.active ? 'text-primary' : 'text-slate-300'}`}>
                                                    check_circle
                                                </span>
                                                <span className="text-sm font-medium text-slate-600 dark:text-slate-400 leading-tight">{feat}</span>
                                            </div>
                                        ))}
                                    </div>

                                    <button
                                        onClick={() => handleSelectPlan(plan.id)}
                                        disabled={updating || plan.active}
                                        className={`w-full h-14 rounded-2xl font-black text-sm uppercase tracking-widest transition-all ${plan.active
                                            ? "bg-primary/20 text-primary cursor-default"
                                            : "bg-slate-900 text-white hover:bg-primary shadow-lg shadow-slate-200 active:scale-95 disabled:opacity-50"
                                            }`}
                                    >
                                        {plan.active ? "Tu Plan Actual" : plan.buttonText}
                                    </button>
                                </div>
                            ))}
                        </div>

                        <div className="mt-20 p-8 rounded-3xl bg-slate-900 text-white relative overflow-hidden">
                            <div className="absolute inset-0 opacity-10 bg-[radial-gradient(#ffffff_1px,transparent_1px)] [background-size:24px_24px]"></div>
                            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
                                <div className="max-w-xl text-center md:text-left">
                                    <h3 className="text-2xl font-black mb-2">??Necesitas un Plan Estudiantil o para Institutos?</h3>
                                    <p className="text-slate-400 font-medium">Ofrecemos descuentos especiales para centros de formaci??n y alumnos certificados. Obt??n acceso a toda la biblioteca por un precio reducido.</p>
                                </div>
                                <Link href="mailto:info@sooferline.com" className="h-14 px-8 bg-white text-slate-900 rounded-2xl flex items-center justify-center font-black text-sm uppercase tracking-widest hover:bg-primary hover:text-white transition-all">
                                    Consultar ahora
                                </Link>
                            </div>
                        </div>
                    </main>

                    <footer className="text-center py-12 border-t border-slate-100 dark:border-slate-800">
                        <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">
                            Precios en USD para etapa de lanzamiento ??? Sooferline IA 2024
                        </p>
                    </footer>
                </>
            )}
        </div>
    );
}

"use client";
import { useState, useEffect, Suspense } from "react";
import { supabase } from "@/lib/supabase";
import { useSearchParams, useRouter } from "next/navigation";
import Navbar from "@/components/Navbar";
import Link from "next/link";

function TiendaContent() {
    const [products, setProducts] = useState<any[]>([]);
    const [filteredProducts, setFilteredProducts] = useState<any[]>([]);
    const [category, setCategory] = useState("Todos");
    const [loading, setLoading] = useState(true);
    const [cart, setCart] = useState<{ product: any, quantity: number }[]>([]);
    const [showCart, setShowCart] = useState(false);

    const searchParams = useSearchParams();
    const router = useRouter();
    const searchBookId = searchParams.get("bookId");

    const [categories, setCategories] = useState<string[]>(["Todos"]);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        const [productsData, categoriesData] = await Promise.all([
            supabase.from("products").select("*").order("created_at", { ascending: false }),
            supabase.from("product_categories").select("name").order("name")
        ]);

        if (categoriesData.data) {
            setCategories(["Todos", ...categoriesData.data.map((c: any) => c.name)]);
        }

        if (productsData.data) {
            setProducts(productsData.data);
            setFilteredProducts(productsData.data);

            // Si viene un ID de libro, filtrar autom??ticamente si existe
            if (searchBookId) {
                const bookMatch = productsData.data.filter((p: any) => p.metadata?.book_id === searchBookId);
                if (bookMatch.length > 0) {
                    setFilteredProducts(bookMatch);
                    setCategory(bookMatch[0].category);
                }
            }
        }
        setLoading(false);
    };

    const filterByCategory = (cat: string) => {
        setCategory(cat);
        if (cat === "Todos") {
            setFilteredProducts(products);
        } else {
            setFilteredProducts(products.filter(p => p.category === cat));
        }
    };

    const addToCart = (product: any) => {
        const existingItem = cart.find(item => item.product.id === product.id);
        if (existingItem) {
            setCart(cart.map(item =>
                item.product.id === product.id
                    ? { ...item, quantity: item.quantity + 1 }
                    : item
            ));
        } else {
            setCart([...cart, { product, quantity: 1 }]);
        }
        alert("??A??adido al carrito!");
    };

    const updateQuantity = (productId: string, delta: number) => {
        setCart(cart.map(item => {
            if (item.product.id === productId) {
                const newQuantity = Math.max(1, item.quantity + delta);
                return { ...item, quantity: newQuantity };
            }
            return item;
        }));
    };

    const removeFromCart = (productId: string) => {
        setCart(cart.filter(item => item.product.id !== productId));
    };

    const confirmarOrden = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) {
            alert("Debes iniciar sesi??n para finalizar tu compra.");
            return;
        }

        const purchasesRows = cart.map(item => ({
            user_id: session.user.id,
            product_id: item.product.id,
            amount: item.product.price * item.quantity
        }));

        const { error } = await supabase.from("user_purchases").insert(purchasesRows);
        if (error) {
            alert("Error al procesar la compra. Verifica la consola.");
            console.error(error);
        } else {
            alert("??Compra exitosa! Tus productos est??n ahora en tu Biblioteca Personal.");
            setCart([]);
            setShowCart(false);
            router.push("/mis-compras");
        }
    };

    const totalItems = cart.reduce((acc, curr) => acc + curr.quantity, 0);
    const totalPrice = cart.reduce((acc, curr) => acc + (curr.product.price * curr.quantity), 0);

    return (
        <div className="min-h-screen bg-slate-50 font-display">
            <Navbar />

            <main className="max-w-7xl mx-auto px-6 py-12 pb-32">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-12">
                    <div className="flex-1">
                        <div className="flex items-center gap-2 mb-2">
                            <span className="material-symbols-outlined text-primary">storefront</span>
                            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Tienda Oficial Sooferline</p>
                        </div>
                        <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none">
                            Cat??logo {category !== "Todos" && <span className="text-primary opacity-30 italic">/ {category}</span>}
                        </h1>
                        <p className="text-slate-500 font-medium mt-3 max-w-lg leading-relaxed italic text-sm">
                            Impulsa tu carrera con recursos premium dise??ados por expertos en Chile.
                        </p>
                    </div>

                    <div className="flex items-center gap-3">
                        <button
                            onClick={() => setShowCart(true)}
                            className="relative p-5 bg-white rounded-[24px] shadow-xl shadow-slate-200 border border-slate-100 group hover:scale-105 active:scale-95 transition-all"
                        >
                            <span className="material-symbols-outlined text-primary text-3xl">shopping_cart</span>
                            {totalItems > 0 && (
                                <span className="absolute -top-1 -right-1 size-7 bg-red-500 text-white text-[11px] font-black rounded-full flex items-center justify-center animate-bounce border-4 border-white">
                                    {totalItems}
                                </span>
                            )}
                        </button>
                    </div>
                </div>

                {/* Filtros */}
                <div className="flex gap-2 mb-10 overflow-x-auto pb-4 custom-scrollbar no-screenshots scroll-smooth">
                    {categories.map(cat => (
                        <button
                            key={cat}
                            onClick={() => filterByCategory(cat)}
                            className={`px-8 py-3.5 rounded-2xl font-black text-[10px] uppercase tracking-[0.15em] transition-all border whitespace-nowrap ${category === cat
                                ? "bg-primary border-primary text-white shadow-xl shadow-primary/20 scale-105"
                                : "bg-white border-slate-200 text-slate-400 hover:border-primary/50"
                                }`}
                        >
                            {cat}
                        </button>
                    ))}
                </div>

                {loading ? (
                    <div className="py-20 flex flex-col items-center justify-center opacity-30">
                        <div className="size-16 border-4 border-slate-200 border-t-primary rounded-full animate-spin mb-4"></div>
                        <p className="font-black uppercase tracking-widest text-xs">Cargando Productos...</p>
                    </div>
                ) : filteredProducts.length === 0 ? (
                    <div className="py-20 text-center bg-white rounded-[40px] border-2 border-dashed border-slate-200">
                        <span className="material-symbols-outlined text-6xl text-slate-200 mb-4">sentiment_dissatisfied</span>
                        <p className="text-xl font-bold text-slate-400">No encontramos productos en esta categor??a</p>
                        <button onClick={() => filterByCategory("Todos")} className="mt-4 text-primary font-black uppercase text-xs tracking-widest hover:underline">Ver todo el cat??logo</button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                        {filteredProducts.map(product => (
                            <div key={product.id} className="bg-white rounded-[40px] overflow-hidden shadow-2xl shadow-slate-200/50 border border-slate-100 hover:border-primary/30 transition-all group flex flex-col h-full animate-in fade-in zoom-in-95 duration-500">
                                <div className="h-64 overflow-hidden relative">
                                    <div className="absolute inset-0 bg-slate-900 group-hover:bg-primary transition-colors duration-500 opacity-0 group-hover:opacity-10 z-10 pointer-events-none"></div>
                                    <img src={product.image_url} alt={product.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                                    <div className="absolute top-6 left-6 px-4 py-1.5 bg-white/95 backdrop-blur-md rounded-full text-[9px] font-black uppercase tracking-widest text-primary shadow-xl z-20">
                                        {product.type}
                                    </div>
                                    <div className="absolute bottom-4 right-6 size-12 bg-white rounded-full flex items-center justify-center shadow-2xl opacity-0 group-hover:opacity-100 translate-y-4 group-hover:translate-y-0 transition-all duration-300 z-20">
                                        <span className="material-symbols-outlined text-primary">visibility</span>
                                    </div>
                                </div>
                                <div className="p-8 flex-1 flex flex-col">
                                    <div className="flex justify-between items-start mb-2">
                                        <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-300">{product.category}</p>
                                        {(product.version || product.visibility !== 'public') && (
                                            <div className="flex gap-1">
                                                {product.version && <span className="px-2 py-0.5 bg-slate-100 rounded text-[8px] font-black text-slate-400">v{product.version}</span>}
                                                {product.visibility && product.visibility !== 'public' && (
                                                    <span className="material-symbols-outlined text-[12px] text-amber-500" title={`Visible solo para: ${product.visibility}`}>lock</span>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                    <h3 className="text-xl font-black text-slate-900 mb-2 leading-tight group-hover:text-primary transition-colors">{product.title}</h3>

                                    {product.tags && product.tags.length > 0 && (
                                        <div className="flex flex-wrap gap-1 mb-4">
                                            {product.tags.map((tag: string, idx: number) => (
                                                <span key={idx} className="px-2 py-1 bg-primary/5 text-primary rounded-md text-[9px] font-bold">#{tag}</span>
                                            ))}
                                        </div>
                                    )}

                                    <div className="mt-auto pt-6 border-t border-slate-50 flex items-center justify-between">
                                        <div>
                                            <p className="text-[9px] font-black uppercase tracking-widest text-slate-400 mb-1 opacity-50">Precio Final</p>
                                            <span className="text-2xl font-black text-slate-900 tracking-tighter">${product.price.toLocaleString('es-CL')}</span>
                                        </div>
                                        <button
                                            onClick={() => addToCart(product)}
                                            className="size-14 rounded-2xl bg-slate-900 text-white flex items-center justify-center hover:bg-primary transition-all shadow-xl active:scale-90"
                                        >
                                            <span className="material-symbols-outlined text-2xl">add_shopping_cart</span>
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </main>

            {/* Cart Modal */}
            {showCart && (
                <div className="fixed inset-0 z-[100] flex justify-end">
                    <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setShowCart(false)}></div>
                    <aside className="relative w-full max-w-md bg-white h-full shadow-2xl p-10 flex flex-col animate-in slide-in-from-right duration-500">
                        <div className="flex justify-between items-center mb-10">
                            <div>
                                <h2 className="text-3xl font-black text-slate-900 tracking-tighter">Mi Compra</h2>
                                <p className="text-slate-400 text-xs font-medium uppercase tracking-widest">Resumen de pedidos</p>
                            </div>
                            <button onClick={() => setShowCart(false)} className="size-12 rounded-full bg-slate-100 flex items-center justify-center hover:bg-red-50 hover:text-red-500 transition-all">
                                <span className="material-symbols-outlined">close</span>
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar no-screenshots">
                            {cart.length === 0 ? (
                                <div className="h-full flex flex-col items-center justify-center text-center opacity-20 py-20">
                                    <span className="material-symbols-outlined text-8xl mb-4">shopping_bag</span>
                                    <p className="font-black uppercase tracking-[0.2em] text-sm leading-relaxed">Tu carrito est?? esperando<br />nuevas oportunidades</p>
                                </div>
                            ) : cart.map((item, idx) => (
                                <div key={idx} className="flex gap-4 p-5 bg-slate-50 rounded-[28px] border border-slate-100 animate-in slide-in-from-bottom duration-300 relative group">
                                    <img src={item.product.image_url} className="size-20 rounded-2xl object-cover shadow-lg" />

                                    <div className="min-w-0 flex-1 flex flex-col justify-center">
                                        <p className="font-black text-sm text-slate-800 leading-tight mb-2 truncate pr-6">{item.product.title}</p>
                                        <div className="flex items-center justify-between">
                                            <p className="text-primary font-black text-lg tracking-tight">${item.product.price.toLocaleString('es-CL')}</p>

                                            {/* Selector de cantidad */}
                                            <div className="flex items-center bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm">
                                                <button onClick={() => updateQuantity(item.product.id, -1)} className="px-3 py-1 text-slate-400 hover:bg-slate-100 hover:text-slate-800 transition-colors material-symbols-outlined text-sm">remove</button>
                                                <span className="px-2 font-black text-sm text-slate-800 w-8 text-center">{item.quantity}</span>
                                                <button onClick={() => updateQuantity(item.product.id, 1)} className="px-3 py-1 text-slate-400 hover:bg-slate-100 hover:text-slate-800 transition-colors material-symbols-outlined text-sm">add</button>
                                            </div>
                                        </div>
                                    </div>
                                    <button onClick={() => removeFromCart(item.product.id)} className="absolute top-4 right-4 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100">
                                        <span className="material-symbols-outlined text-sm">delete</span>
                                    </button>
                                </div>
                            ))}
                        </div>

                        <div className="mt-10 pt-10 border-t-4 border-slate-50">
                            <div className="flex justify-between items-center mb-10">
                                <div>
                                    <span className="text-slate-400 font-black uppercase tracking-[0.2em] text-[10px]">Total a Pagar</span>
                                    <p className="text-4xl font-black text-slate-900 tracking-tighter">${totalPrice.toLocaleString('es-CL')}</p>
                                </div>
                                <div className="bg-primary/10 px-4 py-2 rounded-xl">
                                    <p className="text-primary text-[10px] font-black">CLP</p>
                                </div>
                            </div>
                            <button
                                onClick={confirmarOrden}
                                className="w-full py-6 rounded-[32px] bg-primary text-white font-black uppercase tracking-[0.2em] text-xs shadow-2xl shadow-primary/30 hover:scale-[1.02] active:scale-95 transition-all group overflow-hidden relative"
                            >
                                <span className="relative z-10 flex items-center justify-center gap-3">
                                    Confirmar Orden
                                    <span className="material-symbols-outlined text-sm animate-pulse">arrow_forward_ios</span>
                                </span>
                            </button>
                        </div>
                    </aside>
                </div>
            )}
        </div>
    );
}

export default function TiendaPage() {
    return (
        <Suspense fallback={<div>Cargando tienda...</div>}>
            <TiendaContent />
        </Suspense>
    );
}

"use client";
import Link from "next/link";
import { useRouter } from "next/navigation";

export default function Navbar() {
    return (
        <nav className="h-20 bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-50 px-6 md:px-12 flex items-center justify-between">
            <Link href="/" className="flex items-center gap-2 group">
                <div className="size-10 bg-primary rounded-xl flex items-center justify-center shadow-lg shadow-primary/20 rotate-3 group-hover:rotate-12 transition-transform">
                    <span className="material-symbols-outlined text-white text-2xl">rocket_launch</span>
                </div>
                <span className="text-xl font-black text-slate-900 tracking-tighter">SOOFERLINE <span className="text-primary font-black">IA</span></span>
            </Link>

            <div className="hidden md:flex items-center gap-8">
                <Link href="/biblioteca" className="text-sm font-bold text-slate-600 hover:text-primary transition-colors">Biblioteca</Link>
                <Link href="/tienda" className="text-sm font-bold text-slate-600 hover:text-primary transition-colors">Tienda</Link>
                <Link href="/mis-compras" className="text-sm font-bold text-slate-600 hover:text-primary transition-colors">Mis Compras</Link>
                <Link href="/planes" className="text-sm font-bold text-slate-600 hover:text-primary transition-colors">Planes</Link>
                <Link href="/dashboard" className="px-6 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold hover:bg-primary transition-all shadow-xl shadow-slate-200">Dashboard</Link>
            </div>
        </nav>
    );
}
